# 1. Test that ConfigError can be caught by the try/except Exception blocks
class ConfigError(ValueError):
    pass

def require_loopback(host, what):
    if host not in {"localhost", "127.0.0.1", "::1"}:
        raise ConfigError(f"{what} is not loopback")
    return host

# Test path 1: launch_server_command
def launch_server_command(host):
    host = require_loopback(host, "server bind")
    return f"phoenix serve --host {host}"

# Test path 2: phoenix_endpoint with validation
def phoenix_endpoint(host):
    require_loopback(host, "Phoenix OTLP export")
    return "http://localhost:6006/v1/traces"

# Test path 3: instrument_langchain
def instrument_langchain(host):
    require_loopback(host, "OTLP export")
    return "provider"

# Test path 4: bootstrap_observability catch
def bootstrap_observability(host):
    try:
        return instrument_langchain(host)
    except Exception as e:
        print(f"Caught exception: {type(e).__name__}: {e}")
        return None

print("✓ Test 1: launch_server_command with good host")
try:
    result = launch_server_command("localhost")
    print(f"  Result: {result}")
except Exception as e:
    print(f"  ERROR: {type(e).__name__}: {e}")

